<?php namespace App\Services\Monitoring; use Illuminate\Support\Facades\Log; use Illuminate\Support\Facades\Redis; class PerformanceMonitor { protected array $timers = []; protected float $threshold; public function __construct(float $threshold = 1.0) { $this->threshold = $threshold; } public function start(string $operation): void { $this->timers[$operation] = microtime(true); } public function stop(string $operation, array $context = []): float { if (!isset($this->timers[$operation])) { return 0.0; } $endTime = microtime(true); $duration = $endTime - $this->timers[$operation]; unset($this->timers[$operation]); $this->logPerformance($operation, $duration, $context); if ($duration > $this->threshold) { $this->triggerAlert($operation, $duration, $context); } return $duration; } protected function logPerformance(string $operation, float $duration, array $context): void { $logData = [ 'operation' => $operation, 'duration_seconds' => $duration, 'context' => $context, 'timestamp' => now()->toDateTimeString(), ]; Log::channel('daily')->info("أداء العملية: {$operation} استغرقت {$duration} ثانية.", $logData); Redis::lpush("perf_metrics:{$operation}", json_encode($logData)); } protected function triggerAlert(string $operation, float $duration, array $context): void { Log::channel('stack')->warning("تنبيه: تم تجاوز الحد الزمني للعملية '{$operation}'.", [ 'duration' => $duration, 'threshold' => $this->threshold, 'context' => $context ]); } }